```cpp
#include <utility>
#include <iostream>
#include <vector>
#include <string>

// ─── std::move ───────────────────────────────────────────────────────────────
// Unconditionally casts its argument to an rvalue reference.
// Use it when you KNOW you want to relinquish ownership of a named object.
template<typename T>
void sink(T&& val) {
    // BUG: always moves, even when caller passed an lvalue
    auto stored = std::move(val);  // steals from lvalue — caller loses data!
    (void)stored;
}

// ─── std::forward ────────────────────────────────────────────────────────────
// Conditionally casts to rvalue — only if the original argument was an rvalue.
// This is "perfect forwarding": preserves the value category of the caller.
template<typename T>
void forward_sink(T&& val) {
    // CORRECT: forwards as lvalue if T=SomeType&, rvalue if T=SomeType
    auto stored = std::forward<T>(val);
    (void)stored;
}

// ─── The Classic Bug ─────────────────────────────────────────────────────────
template<typename Container, typename T>
void buggy_emplace(Container& c, T&& item) {
    // std::move here is WRONG: if caller passes an lvalue, we steal it
    // on the first call — subsequent forwarding in a loop would use a
    // moved-from value.
    c.emplace_back(std::move(item));  // BUG when T& (lvalue ref)
}

template<typename Container, typename T>
void correct_emplace(Container& c, T&& item) {
    c.emplace_back(std::forward<T>(item));  // OK: lvalue stays lvalue
}

// ─── Forwarding reference vs rvalue reference ─────────────────────────────────
// T&& in a template is a FORWARDING (universal) reference — T can deduce as
// lvalue-ref or rvalue-ref depending on the argument.
// A non-template rvalue reference (std::string&&) does NOT forward — it is
// always an rvalue reference.
void takes_rvalue(std::string&& s) {
    // s is a NAMED lvalue here (it has a name!), so to move it you must
    // explicitly call std::move:
    std::string local = std::move(s);  // correct — we own s
    (void)local;
}

int main() {
    std::vector<std::string> v;
    std::string s = "hello";

    // Passing lvalue — buggy_emplace will MOVE from s (caller loses it!)
    buggy_emplace(v, s);
    std::cout << "After buggy_emplace, s = '" << s << "'\n";  // s is now ""

    s = "world";
    correct_emplace(v, s);  // lvalue: s is copied, not moved
    std::cout << "After correct_emplace, s = '" << s << "'\n";  // s intact

    correct_emplace(v, std::string{"tmp"});  // rvalue: moved in, zero copies
}
```

**Key rules:**
| Situation | Use |
|---|---|
| Named object you are done with | `std::move` |
| Forwarding reference in a template | `std::forward<T>` |
| Non-template rvalue reference parameter | `std::move` (it's a named lvalue) |
| Anything else | Neither — just pass by value or reference |

`std::forward<T>(x)` is equivalent to `static_cast<T&&>(x)`. When `T` is deduced as `Foo&`, reference collapsing makes `Foo& &&` → `Foo&` (lvalue). When `T` is `Foo`, `Foo&&` stays an rvalue. That is the entire mechanism.

```cpp
#include <iostream>
#include <string>

struct Widget {
    Widget() { std::cout << "construct\n"; }
    Widget(const Widget&) { std::cout << "copy\n"; }
    Widget(Widget&&) noexcept { std::cout << "move\n"; }
    ~Widget() { std::cout << "destroy\n"; }
};

// ─── RVO: unnamed temporary ───────────────────────────────────────────────────
// C++17 mandates copy elision here — the Widget is constructed directly in the
// caller's storage. No copy, no move, zero overhead.
Widget make_rvo() {
    return Widget{};  // prvalue: mandatory copy elision (C++17)
}

// ─── NRVO: named local variable ──────────────────────────────────────────────
// Not guaranteed by the standard, but all major compilers (GCC/Clang/MSVC)
// apply NRVO at -O1 and above. Zero copies in practice.
Widget make_nrvo() {
    Widget w;       // constructed once
    w = Widget{};  // simulate some work
    return w;       // NRVO: compiler constructs w directly in caller's slot
}

// ─── Anti-pattern: std::move in return defeats NRVO ──────────────────────────
// By writing std::move(w), you explicitly request an rvalue reference.
// This prevents the compiler from applying NRVO because the return expression
// is no longer a plain name — it's a cast.
// Result: an extra move construction happens.
Widget make_moved() {
    Widget w;
    return std::move(w);  // BAD: disables NRVO, forces a move construction
}

// ─── Legitimate use: moving a sub-object or non-local ────────────────────────
struct Owner {
    Widget w;
    Widget release() {
        return std::move(w);  // OK: w is a member, not a local — NRVO can't apply
    }
};

int main() {
    std::cout << "--- RVO ---\n";
    auto a = make_rvo();     // prints: construct (just once)

    std::cout << "--- NRVO ---\n";
    auto b = make_nrvo();    // prints: construct, construct, destroy (the temporary)
                              // with NRVO enabled: construct (just once)

    std::cout << "--- Defeated NRVO ---\n";
    auto c = make_moved();   // prints: construct, move, destroy
    //                                  ^^^^ extra move that NRVO would have avoided
    (void)a; (void)b; (void)c;
}
```

**Rules to internalize:**
1. **Mandatory elision (C++17):** When you `return` a prvalue (a temporary), the standard guarantees no copy or move — the object is built in place.
2. **NRVO (optional but reliable):** When you return a named local whose type matches the return type, compilers elide the copy/move. You get it for free.
3. **Never `return std::move(local_var)`** — you pay for a move that NRVO would have eliminated entirely. Compilers also emit a warning for this pattern.
4. **Do use `std::move`** when returning a data member, a local of a different type, or when the return is conditional (NRVO cannot apply across branches to different variables).

```cpp
#include <memory>
#include <vector>
#include <iostream>
#include <algorithm>
#include <functional>

// ─── Without weak_ptr: cycle causes leak ─────────────────────────────────────
struct Node {
    std::string name;
    std::shared_ptr<Node> next;  // BAD: if two nodes point to each other,
                                  // ref counts never reach zero — memory leak
    ~Node() { std::cout << "~Node(" << name << ")\n"; }
};

void demo_cycle() {
    auto a = std::make_shared<Node>("A");
    auto b = std::make_shared<Node>("B");
    a->next = b;
    b->next = a;  // cycle: a -> b -> a
    // Both nodes leak — their destructors are never called
}

// ─── Observer pattern: the right fix ─────────────────────────────────────────
// Subject holds weak_ptr to observers — it does not extend their lifetime.
// Observers hold shared_ptr to subject — they keep the subject alive.
class Subject;

class Observer : public std::enable_shared_from_this<Observer> {
public:
    explicit Observer(std::string name) : name_{std::move(name)} {}
    ~Observer() { std::cout << "~Observer(" << name_ << ")\n"; }

    void on_event(const std::string& msg) {
        std::cout << name_ << " received: " << msg << "\n";
    }

private:
    std::string name_;
};

class Subject {
public:
    void subscribe(std::shared_ptr<Observer> obs) {
        // Store WEAK reference — subject doesn't keep observers alive
        observers_.push_back(obs);
    }

    void notify(const std::string& msg) {
        // Sweep dead observers while notifying live ones
        std::erase_if(observers_, [&](const std::weak_ptr<Observer>& wp) {
            if (auto obs = wp.lock()) {  // lock() returns shared_ptr or nullptr
                obs->on_event(msg);
                return false;  // keep in list
            }
            return true;  // observer is dead — remove
        });
    }

private:
    std::vector<std::weak_ptr<Observer>> observers_;  // KEY: weak references
};

int main() {
    Subject subject;

    {
        auto obs1 = std::make_shared<Observer>("Logger");
        auto obs2 = std::make_shared<Observer>("Metrics");
        subject.subscribe(obs1);
        subject.subscribe(obs2);

        subject.notify("tick");  // both receive it
        // obs2 goes out of scope here — destroyed immediately (ref count = 0)
    }

    subject.notify("tock");  // only obs1 receives; dead obs2 is swept
    // obs1 destroyed at end of main
}
```

**Ownership rule for graphs:**
- Parent → child: `shared_ptr` (parent keeps child alive)
- Child → parent: `weak_ptr` (back-pointer without ownership)
- Observer → subject: `shared_ptr` (if observer needs subject to exist)
- Subject → observer: `weak_ptr` (subject doesn't dictate observer lifetime)

`weak_ptr::lock()` is the only safe way to access the object — it atomically checks the ref count and returns nullptr if the object has been destroyed, preventing use-after-free.

```cpp
#include <utility>
#include <functional>
#include <iostream>

// ─── Primary template: non-type-erased, zero overhead ────────────────────────
// Stores the callable directly — no heap allocation, no virtual dispatch.
template<typename F>
class ScopeGuard {
public:
    explicit ScopeGuard(F&& f) noexcept(std::is_nothrow_move_constructible_v<F>)
        : fn_{std::forward<F>(f)}, active_{true} {}

    ~ScopeGuard() noexcept {
        if (active_) {
            try { fn_(); }
            catch (...) {}  // destructor must not throw
        }
    }

    // Allow caller to cancel the guard (commit pattern)
    void dismiss() noexcept { active_ = false; }

    ScopeGuard(ScopeGuard&&) = delete;
    ScopeGuard(const ScopeGuard&) = delete;
    ScopeGuard& operator=(const ScopeGuard&) = delete;
    ScopeGuard& operator=(ScopeGuard&&) = delete;

private:
    F    fn_;
    bool active_;
};

// Deduction guide so you can write ScopeGuard{[]{}} without <F>
template<typename F>
ScopeGuard(F) -> ScopeGuard<F>;

// ─── Convenience macro (optional) ─────────────────────────────────────────────
#define DEFER(code) ScopeGuard DEFER_##__LINE__{ [&]{ code; } }

// ─── Commit/Rollback pattern ──────────────────────────────────────────────────
// Useful for transactional operations: set up rollback, dismiss on success.
void transactional_write(bool fail) {
    bool committed = false;
    auto rollback = ScopeGuard{[&] {
        if (!committed) std::cout << "Rolling back\n";
    }};

    // ... do work ...
    if (fail) throw std::runtime_error{"write failed"};

    committed = true;
    rollback.dismiss();  // success — cancel the rollback guard
    std::cout << "Committed\n";
}

int main() {
    // Basic defer
    {
        DEFER(std::cout << "exiting scope\n");
        std::cout << "in scope\n";
    }  // prints: in scope, exiting scope

    // Exception-safe resource management
    {
        auto* buf = new int[256];
        ScopeGuard cleanup{[&]{ delete[] buf; std::cout << "buf freed\n"; }};
        // use buf ...
        // freed even if exception thrown
    }

    // Commit/rollback
    try { transactional_write(false); } catch (...) {}
    try { transactional_write(true);  } catch (...) {}
}
```

**Key design points:**
- Template parameter `F` avoids `std::function` overhead — no heap allocation, no type erasure.
- `noexcept` specifiers propagate correctly: if your lambda is noexcept, the guard constructor is too.
- `dismiss()` enables the commit pattern: arm the cleanup on entry, disarm it on success.
- The `try/catch` in the destructor is intentional — destructors must not propagate exceptions during stack unwinding (undefined behavior if they do and another exception is active).

```cpp
#include <memory>
#include <unistd.h>   // close(), read(), write()
#include <fcntl.h>    // open(), O_RDONLY
#include <stdexcept>
#include <string>
#include <cerrno>
#include <cstring>
#include <iostream>

// ─── Option 1: function pointer deleter (simple but adds one pointer of size)
struct CloseDeleter {
    void operator()(int* fd) const noexcept {
        if (*fd >= 0) ::close(*fd);
        delete fd;
    }
};

// ─── Option 2: stateless struct deleter for int handle directly
// unique_ptr<int, CloseDeleter> doesn't work cleanly because unique_ptr
// needs a pointer type. Wrap the fd in a struct to use it as a pointer.

// ─── Better: a thin wrapper so fd IS the managed object ─────────────────────
struct Fd {
    int value;
    explicit Fd(int v) noexcept : value{v} {}
};

struct FdDeleter {
    void operator()(Fd* p) const noexcept {
        if (p && p->value >= 0) ::close(p->value);
        delete p;
    }
};

using UniqueFd = std::unique_ptr<Fd, FdDeleter>;

UniqueFd open_file(const char* path) {
    int fd = ::open(path, O_RDONLY);
    if (fd < 0)
        throw std::runtime_error{std::string{"open: "} + std::strerror(errno)};
    return UniqueFd{new Fd{fd}};
}

// ─── Option 3 (idiomatic): RAII class that wraps int directly ─────────────────
class FileDescriptor {
public:
    static constexpr int invalid = -1;

    explicit FileDescriptor(int fd = invalid) noexcept : fd_{fd} {}
    ~FileDescriptor() noexcept { close(); }

    FileDescriptor(FileDescriptor&& o) noexcept : fd_{o.fd_} { o.fd_ = invalid; }
    FileDescriptor& operator=(FileDescriptor&& o) noexcept {
        if (this != &o) { close(); fd_ = o.fd_; o.fd_ = invalid; }
        return *this;
    }
    FileDescriptor(const FileDescriptor&) = delete;
    FileDescriptor& operator=(const FileDescriptor&) = delete;

    int get() const noexcept { return fd_; }
    bool valid() const noexcept { return fd_ != invalid; }
    operator bool() const noexcept { return valid(); }

    // Release ownership without closing
    int release() noexcept { int tmp = fd_; fd_ = invalid; return tmp; }

    ssize_t read(void* buf, std::size_t n) const {
        return ::read(fd_, buf, n);
    }

private:
    void close() noexcept {
        if (fd_ != invalid) { ::close(fd_); fd_ = invalid; }
    }
    int fd_;
};

int main() {
    try {
        FileDescriptor fd{::open("/etc/hostname", O_RDONLY)};
        if (!fd) throw std::runtime_error{"cannot open /etc/hostname"};

        char buf[256] = {};
        ssize_t n = fd.read(buf, sizeof(buf) - 1);
        std::cout << "hostname: " << buf;
        // fd closed automatically here
    } catch (const std::exception& e) {
        std::cerr << e.what() << "\n";
    }
}
```

**When to use which approach:**
- `unique_ptr` with custom deleter: great for ad-hoc wrapping of C library handles that give you a pointer (e.g., `fclose`, `EVP_MD_CTX_free`, `SDL_DestroyWindow`).
- A bespoke RAII class (option 3): cleaner when the handle is a non-pointer (int fd, HANDLE, GLuint) — avoids the awkward extra heap allocation.
- Never use `std::function` as a deleter — it's heap-allocated and kills move-only semantics of `unique_ptr`.

