**std::format advantages over printf/stringstream:**
- Type-safe: format string is checked against argument types at compile time (when literal).
- Extensible: `std::formatter<T>` specialization works for any type.
- No locale surprises: locale-independent by default (use `std::vformat` with locale if needed).
- `std::format_to` / `std::format_to_n` write directly to iterators/buffers — zero heap allocation.

```cpp
#include <expected>
#include <string>
#include <string_view>
#include <charconv>
#include <vector>
#include <iostream>
#include <system_error>

// ─── Error type ───────────────────────────────────────────────────────────────
struct ParseError {
    enum class Code { empty_input, invalid_number, out_of_range, unexpected_char };
    Code code;
    std::string message;
    std::size_t position{0};

    static ParseError make(Code c, std::string msg, std::size_t pos = 0) {
        return {c, std::move(msg), pos};
    }
};

template<typename T>
using Result = std::expected<T, ParseError>;

// ─── Parsing primitives ───────────────────────────────────────────────────────
Result<std::string_view> strip_whitespace(std::string_view s) {
    if (s.empty()) return std::unexpected{ParseError::make(
        ParseError::Code::empty_input, "empty input")};
    auto start = s.find_first_not_of(" \t\n\r");
    return (start == std::string_view::npos) ? std::string_view{} : s.substr(start);
}

Result<int64_t> parse_integer(std::string_view s) {
    if (s.empty()) return std::unexpected{
        ParseError::make(ParseError::Code::empty_input, "expected integer")};

    int64_t value;
    auto [ptr, ec] = std::from_chars(s.data(), s.data() + s.size(), value);

    if (ec == std::errc::result_out_of_range)
        return std::unexpected{ParseError::make(
            ParseError::Code::out_of_range, "integer out of range")};
    if (ec != std::errc{})
        return std::unexpected{ParseError::make(
            ParseError::Code::invalid_number, "invalid integer: " + std::string{s})};

    return value;
}

Result<std::vector<int64_t>> parse_csv_integers(std::string_view input) {
    std::vector<int64_t> results;
    std::size_t pos = 0;

    while (pos < input.size()) {
        auto end = input.find(',', pos);
        auto token = (end == std::string_view::npos)
                     ? input.substr(pos)
                     : input.substr(pos, end - pos);

        // Chain: strip whitespace then parse integer
        auto stripped = strip_whitespace(token);
        if (!stripped) return std::unexpected{stripped.error()};

        auto num = parse_integer(*stripped);
        if (!num) return std::unexpected{num.error()};

        results.push_back(*num);
        pos = (end == std::string_view::npos) ? input.size() : end + 1;
    }

    return results;
}

// ─── Monadic chaining (C++23 and_then / or_else) ─────────────────────────────
Result<int64_t> parse_positive(std::string_view s) {
    return parse_integer(s)
        .and_then([](int64_t v) -> Result<int64_t> {
            if (v <= 0) return std::unexpected{ParseError::make(
                ParseError::Code::out_of_range, "expected positive, got " + std::to_string(v))};
            return v;
        })
        .or_else([](ParseError e) -> Result<int64_t> {
            // Could recover or re-map errors here
            return std::unexpected{std::move(e)};
        });
}

void print_error(const ParseError& e) {
    const char* codes[] = {"empty_input","invalid_number","out_of_range","unexpected_char"};
    std::cerr << "ParseError[" << codes[static_cast<int>(e.code)] << "]: "
              << e.message << " at pos " << e.position << "\n";
}

int main() {
    // Success path
    if (auto r = parse_csv_integers("1, 2, 3, 42, -7")) {
        for (int64_t n : *r) std::cout << n << " ";
        std::cout << "\n";  // 1 2 3 42 -7
    }

    // Error path — no exceptions, no goto, no out-params
    if (auto r = parse_csv_integers("1, 2, abc, 4"); !r)
        print_error(r.error());
    // ParseError[invalid_number]: invalid integer: abc at pos 0

    // Monadic chain
    for (auto input : {"42", "-5", "not_a_number"}) {
        auto r = parse_positive(input);
        if (r) std::cout << input << " -> " << *r << "\n";
        else   print_error(r.error());
    }
}
```

**Why `std::expected` over exceptions:**
- Errors are visible in the type signature — callers cannot ignore them without a `*` dereference.
- Zero overhead on the success path in most implementations.
- `and_then` / `or_else` (C++23) enable railway-oriented programming without nested if-chains.
- Safe to use across DLL boundaries and in `noexcept` contexts.

```cpp
#include <compare>
#include <string>
#include <vector>
#include <algorithm>
#include <iostream>

// ─── Automatic comparison synthesis ──────────────────────────────────────────
struct Version {
    int major, minor, patch;
    std::string pre_release;  // "" = stable, "alpha" < "beta" < stable

    // Declare defaulted spaceship → compiler generates <, <=, >, >=, ==, !=
    // Default ordering for aggregates: lexicographic, member by member
    // NOTE: std::string has spaceship support, so this just works.
    auto operator<=>(const Version&) const = default;
};

// ─── Custom ordering: partially ordered ──────────────────────────────────────
// Return type encodes the ordering category:
//   strong_ordering  — total order, no incomparables (integers)
//   weak_ordering    — total but some equivalents differ (case-insensitive strings)
//   partial_ordering — some pairs are unordered (floating-point NaN)
struct SemanticVersion {
    int major, minor, patch;

    std::strong_ordering operator<=>(const SemanticVersion& o) const noexcept {
        if (auto cmp = major <=> o.major; cmp != 0) return cmp;
        if (auto cmp = minor <=> o.minor; cmp != 0) return cmp;
        return patch <=> o.patch;
    }
    bool operator==(const SemanticVersion&) const = default;  // needed for ==
};

// ─── Heterogeneous comparison ─────────────────────────────────────────────────
struct Weight {
    double kg;
    // partial_ordering because NaN != NaN
    std::partial_ordering operator<=>(const Weight& o) const noexcept {
        return kg <=> o.kg;
    }
    bool operator==(const Weight&) const = default;
};

// ─── Old-style vs new-style ───────────────────────────────────────────────────
struct OldStyle {
    int val;
    // Required 6 functions: <, <=, >, >=, ==, !=
    bool operator< (const OldStyle& o) const { return val <  o.val; }
    bool operator<=(const OldStyle& o) const { return val <= o.val; }
    bool operator> (const OldStyle& o) const { return val >  o.val; }
    bool operator>=(const OldStyle& o) const { return val >= o.val; }
    bool operator==(const OldStyle& o) const { return val == o.val; }
    bool operator!=(const OldStyle& o) const { return val != o.val; }
};

struct NewStyle {
    int val;
    auto operator<=>(const NewStyle&) const = default;  // all 6 generated
};

int main() {
    Version v1{1, 2, 3, ""};
    Version v2{1, 2, 4, ""};
    Version v3{1, 2, 3, "alpha"};

    std::cout << std::boolalpha;
    std::cout << (v1 < v2)  << "\n";  // true
    std::cout << (v1 > v3)  << "\n";  // true ("" > "alpha" alphabetically — note: not semantic!)
    std::cout << (v1 == v1) << "\n";  // true
    std::cout << (v1 != v2) << "\n";  // true

    // Works with std::sort, std::min, std::max, std::clamp out of the box
    std::vector<SemanticVersion> versions = {{2,0,0},{1,9,9},{1,10,0},{2,0,1}};
    std::sort(versions.begin(), versions.end());
    for (auto& v : versions)
        std::cout << v.major << "." << v.minor << "." << v.patch << "\n";
    // 1.9.9, 1.10.0, 2.0.0, 2.0.1

    // Three-way result
    auto cmp = SemanticVersion{1,0,0} <=> SemanticVersion{2,0,0};
    if (cmp < 0)  std::cout << "less\n";
    if (cmp == 0) std::cout << "equal\n";
    if (cmp > 0)  std::cout << "greater\n";
}
```

**Rules:**
- `= default` spaceship compares members in declaration order, lexicographically.
- If all members have `strong_ordering`, the class gets `strong_ordering`.
- If any member is `weak_` or `partial_ordering`, the weakest category propagates.
- You still need `operator==` separately if you only declare spaceship — or use `= default` for both.
- The compiler rewrites `a < b` as `(a <=> b) < 0`, so you get all six operators for free.

```cpp
#include <iostream>
#include <string>
#include <sstream>
#include <chrono>

// ─── CRTP base: adds serialization to any derived class ──────────────────────
// The derived class only needs to implement serialize_impl().
// The base provides the public interface, dispatching to the derived impl
// at compile time via static_cast — zero virtual dispatch cost.
template<typename Derived>
class Serializable {
public:
    std::string serialize() const {
        return static_cast<const Derived*>(this)->serialize_impl();
    }

    static Derived deserialize(std::string_view data) {
        return Derived::deserialize_impl(data);
    }

    void save_to_stream(std::ostream& os) const {
        os << serialize();
    }
};

// ─── CRTP base: adds comparison operators from a single compare() method ──────
template<typename Derived>
class Comparable {
public:
    bool operator==(const Derived& o) const { return derived().compare(o) == 0; }
    bool operator!=(const Derived& o) const { return derived().compare(o) != 0; }
    bool operator< (const Derived& o) const { return derived().compare(o) <  0; }
    bool operator<=(const Derived& o) const { return derived().compare(o) <= 0; }
    bool operator> (const Derived& o) const { return derived().compare(o) >  0; }
    bool operator>=(const Derived& o) const { return derived().compare(o) >= 0; }
private:
    const Derived& derived() const { return *static_cast<const Derived*>(this); }
};

// ─── CRTP base: adds benchmarking/timing as a mixin ──────────────────────────
template<typename Derived>
struct Benchmarkable {
    template<typename... Args>
    auto timed_call(Args&&... args) {
        auto t0 = std::chrono::high_resolution_clock::now();
        auto result = static_cast<Derived*>(this)->run(std::forward<Args>(args)...);
        auto t1 = std::chrono::high_resolution_clock::now();
        auto us = std::chrono::duration_cast<std::chrono::microseconds>(t1 - t0).count();
        std::cout << "[bench] " << us << "us\n";
        return result;
    }
};

// ─── Concrete types using multiple CRTP mixins ────────────────────────────────
struct Point
    : Serializable<Point>
    , Comparable<Point>
{
    int x, y;
    Point(int x = 0, int y = 0) : x{x}, y{y} {}

    // Implement the interface expected by CRTP bases
    std::string serialize_impl() const {
        return std::to_string(x) + "," + std::to_string(y);
    }
    static Point deserialize_impl(std::string_view s) {
        auto comma = s.find(',');
        return {std::stoi(std::string{s.substr(0, comma)}),
                std::stoi(std::string{s.substr(comma+1)})};
    }
    int compare(const Point& o) const {
        if (x != o.x) return x - o.x;
        return y - o.y;
    }
};

struct Sorter : Benchmarkable<Sorter> {
    std::vector<int> data;
    void run() {
        std::sort(data.begin(), data.end());
    }
};

int main() {
    Point a{1, 2}, b{3, 4}, c{1, 2};
    std::cout << (a < b)  << "\n";  // 1
    std::cout << (a == c) << "\n"; // 1
    std::cout << a.serialize() << "\n"; // "1,2"

    auto p = Point::deserialize("7,9");
    std::cout << p.x << "," << p.y << "\n"; // 7,9

    Sorter s;
    s.data = {5,3,1,4,2};
    s.timed_call();
    for (int n : s.data) std::cout << n << " "; // 1 2 3 4 5
    std::cout << "\n";
}
```

**CRTP vs virtual dispatch:**
| | CRTP | Virtual |
|---|---|---|
| Dispatch | Static (compile-time) | Dynamic (runtime vtable) |
| Overhead | Zero | Pointer indirection + branch |
| Inlining | Yes | Rarely |
| Code bloat | Per instantiation | Shared vtable |
| Multiple bases | Yes (stack mixins) | Diamond problem |

CRTP is ideal for **mixins** — adding orthogonal behavior (logging, serialization, benchmarking) without coupling. The key insight: `static_cast<Derived*>(this)` in the base is safe because the template parameter `Derived` must inherit from `Base<Derived>`.

```cpp
#include <type_traits>
#include <iterator>
#include <vector>
#include <list>
#include <iostream>
#include <string>

// ─── Tag dispatch vs if constexpr ────────────────────────────────────────────
// Tag dispatch: pass an empty struct as a function argument to select overload.
// The compiler picks the overload at call site — readable, extensible.
// if constexpr: conditional compilation inside one function body.
// Use tag dispatch when the implementations are substantially different
// and you want separate functions (better readability, separate testing).

// ─── Classic example: advance() with iterator categories ──────────────────────
template<typename Iter>
void advance_impl(Iter& it, std::ptrdiff_t n,
                  std::random_access_iterator_tag) {
    it += n;  // O(1) for random-access iterators
    std::cout << "[random_access] advanced by " << n << "\n";
}

template<typename Iter>
void advance_impl(Iter& it, std::ptrdiff_t n,
                  std::bidirectional_iterator_tag) {
    // O(n), but can go backwards
    if (n > 0) while (n--) ++it;
    else       while (n++) --it;
    std::cout << "[bidirectional] stepped " << n << "\n";
}

template<typename Iter>
void advance_impl(Iter& it, std::ptrdiff_t n,
                  std::forward_iterator_tag) {
    while (n-- > 0) ++it;  // forward only
    std::cout << "[forward] stepped forward\n";
}

// Public API: dispatches to the right impl via the tag
template<typename Iter>
void my_advance(Iter& it, std::ptrdiff_t n) {
    // typename iterator_traits<Iter>::iterator_category is the TAG TYPE
    advance_impl(it, n, typename std::iterator_traits<Iter>::iterator_category{});
}

// ─── Custom dispatch: integer vs floating-point serialization ─────────────────
struct integer_tag   {};
struct floating_tag  {};
struct other_tag     {};

template<typename T>
auto dispatch_tag() {
    if constexpr (std::is_integral_v<T>)       return integer_tag{};
    else if constexpr (std::is_floating_point_v<T>) return floating_tag{};
    else                                         return other_tag{};
}

template<typename T>
std::string serialize_impl(const T& v, integer_tag) {
    return "int:" + std::to_string(v);
}

template<typename T>
std::string serialize_impl(const T& v, floating_tag) {
    return "float:" + std::to_string(v);
}

template<typename T>
std::string serialize_impl(const T& v, other_tag) {
    return "other:" + std::string{v};
}

template<typename T>
std::string serialize(const T& v) {
    return serialize_impl(v, dispatch_tag<T>());
}

// ─── Comparison: if constexpr version ────────────────────────────────────────
template<typename T>
std::string serialize_ifc(const T& v) {
    if constexpr (std::is_integral_v<T>)
        return "int:" + std::to_string(v);
    else if constexpr (std::is_floating_point_v<T>)
        return "float:" + std::to_string(v);
    else
        return "other:" + std::string{v};
    // Pro: single function, easy to read
    // Con: not extensible — adding a new branch requires editing this function
    //      Tag dispatch: add a new tag + overload, touching nothing else
}

int main() {
    std::vector<int> v = {1,2,3,4,5};
    auto vit = v.begin();
    my_advance(vit, 3);        // [random_access] advanced by 3
    std::cout << *vit << "\n"; // 4

    std::list<int> l = {1,2,3,4,5};
    auto lit = l.begin();
    my_advance(lit, 2);        // [bidirectional] stepped
    std::cout << *lit << "\n"; // 3

    std::cout << serialize(42)    << "\n";  // int:42
    std::cout << serialize(3.14)  << "\n";  // float:3.140000
    std::cout << serialize(std::string_view{"hi"}) << "\n";  // other:hi
}
```

**When to prefer tag dispatch over `if constexpr`:**
- The implementations are complex and deserve separate functions for readability and testing.
- You want extensibility: new categories can be added by new overloads without modifying existing code (open/closed principle).
- Pre-C++17 code: tag dispatch works in C++11; `if constexpr` does not.
- When overloads need to call each other (e.g., `bidirectional_tag` can fall through to `forward_tag` via base-class tag inheritance in iterator hierarchy).

```cpp
#include <vector>
#include <algorithm>
#include <numeric>
#include <stdexcept>
#include <iostream>
#include <type_traits>
#include <chrono>

// ─── Sorting policies ─────────────────────────────────────────────────────────
struct StdSortPolicy {
    template<typename Iter>
    static void sort(Iter begin, Iter end) {
        std::sort(begin, end);
    }
};

struct StableSortPolicy {
    template<typename Iter>
    static void sort(Iter begin, Iter end) {
        std::stable_sort(begin, end);
    }
};

struct NoSortPolicy {
    template<typename Iter>
    static void sort(Iter, Iter) {}  // no-op: data assumed pre-sorted
};

// ─── Validation policies ──────────────────────────────────────────────────────
struct NoValidation {
    template<typename Container>
    static void validate(const Container&) {}  // zero overhead
};

struct BoundsValidation {
    template<typename Container>
    static void validate(const Container& c) {
        if (c.empty()) throw std::invalid_argument{"container is empty"};
    }
};

struct SortedValidation {
    template<typename Container>
    static void validate(const Container& c) {
        if (!std::is_sorted(c.begin(), c.end()))
            throw std::runtime_error{"container is not sorted"};
    }
};

// ─── Statistics computation policies ──────────────────────────────────────────
struct MeanPolicy {
    template<typename Container>
    static double compute(const Container& c) {
        return static_cast<double>(std::accumulate(c.begin(), c.end(), 0LL)) / c.size();
    }
};

struct MedianPolicy {
    template<typename Container>
    static double compute(const Container& c) {
        // Assumes data is already sorted (compose with StdSortPolicy)
        auto n = c.size();
        if (n % 2 == 0)
            return (c[n/2 - 1] + c[n/2]) / 2.0;
        return c[n/2];
    }
};

struct TrimmedMeanPolicy {
    template<typename Container>
    static double compute(const Container& c) {
        // Drop top/bottom 10%
        auto trim = c.size() / 10;
        if (c.size() <= 2 * trim) return 0.0;
        double sum = std::accumulate(c.begin() + trim, c.end() - trim, 0.0);
        return sum / (c.size() - 2 * trim);
    }
};

// ─── Policy-based Analyzer: compile-time composition ──────────────────────────
template<
    typename SortPolicy       = StdSortPolicy,
    typename ValidationPolicy = BoundsValidation,
    typename StatPolicy       = MeanPolicy
>
class Analyzer {
public:
    double analyze(std::vector<int> data) {
        ValidationPolicy::validate(data);   // check pre-conditions
        SortPolicy::sort(data.begin(), data.end());  // sort if policy requires
        return StatPolicy::compute(data);   // compute statistic
    }
};

// ─── Alias pre-canned configurations ─────────────────────────────────────────
using FastMean   = Analyzer<NoSortPolicy,     NoValidation,     MeanPolicy>;
using SafeMedian = Analyzer<StdSortPolicy,    BoundsValidation, MedianPolicy>;
using RobustStat = Analyzer<StableSortPolicy, SortedValidation, TrimmedMeanPolicy>;

int main() {
    std::vector<int> data = {5, 1, 9, 3, 7, 2, 8, 4, 6, 10};

    FastMean   fast;
    SafeMedian median;

    std::cout << "Mean:   " << fast.analyze(data)   << "\n";  // 5.5
    std::cout << "Median: " << median.analyze(data) << "\n"; // 5.5

    // Custom one-off combination:
    Analyzer<StdSortPolicy, BoundsValidation, TrimmedMeanPolicy> custom;
    std::cout << "Trimmed mean: " << custom.analyze(data) << "\n";

    // Empty container triggers BoundsValidation
    try {
        median.analyze({});
    } catch (const std::invalid_argument& e) {
        std::cout << "Caught: " << e.what() << "\n";
    }
}
```

**Policy design advantages:**
- **Zero overhead:** all dispatch is at compile time — no virtual tables, no function pointers.
- **Open/closed:** add a new sort or stat policy without modifying `Analyzer`.
- **Testability:** swap `BoundsValidation` for `NoValidation` in benchmarks; inject `MockSortPolicy` in tests.
- **Self-documenting:** `Analyzer<StdSortPolicy, BoundsValidation, MedianPolicy>` reads like a specification.

This is how the C++ standard library is designed internally (e.g., `std::allocator` as a policy, `Traits` in `std::basic_string`).

```cpp
#include <type_traits>
#include <iostream>
#include <string_view>

// ─── Type list ────────────────────────────────────────────────────────────────
template<typename... Ts>
struct TypeList {};

// ─── Length ───────────────────────────────────────────────────────────────────
template<typename List>
struct Length;

template<typename... Ts>
struct Length<TypeList<Ts...>> : std::integral_constant<std::size_t, sizeof...(Ts)> {};

template<typename List>
constexpr std::size_t length_v = Length<List>::value;

// ─── At<N> ────────────────────────────────────────────────────────────────────
template<std::size_t N, typename List>
struct At;

template<typename Head, typename... Tail>
struct At<0, TypeList<Head, Tail...>> {
    using type = Head;
};

template<std::size_t N, typename Head, typename... Tail>
struct At<N, TypeList<Head, Tail...>> {
    using type = typename At<N-1, TypeList<Tail...>>::type;
};

template<std::size_t N, typename List>
using at_t = typename At<N, List>::type;

// ─── Prepend ──────────────────────────────────────────────────────────────────
template<typename T, typename List>
struct Prepend;

template<typename T, typename... Ts>
struct Prepend<T, TypeList<Ts...>> {
    using type = TypeList<T, Ts...>;
};

template<typename T, typename List>
using prepend_t = typename Prepend<T, List>::type;

// ─── Filter ───────────────────────────────────────────────────────────────────
// Keeps types for which Predicate<T>::value is true
template<template<typename> class Pred, typename List>
struct Filter;

template<template<typename> class Pred>
struct Filter<Pred, TypeList<>> {
    using type = TypeList<>;  // base case
};

template<template<typename> class Pred, typename Head, typename... Tail>
struct Filter<Pred, TypeList<Head, Tail...>> {
    using tail_filtered = typename Filter<Pred, TypeList<Tail...>>::type;
    using type = std::conditional_t<
        Pred<Head>::value,
        prepend_t<Head, tail_filtered>,
        tail_filtered
    >;
};

template<template<typename> class Pred, typename List>
using filter_t = typename Filter<Pred, List>::type;

// ─── Transform ────────────────────────────────────────────────────────────────
template<template<typename> class F, typename List>
struct Transform;

template<template<typename> class F>
struct Transform<F, TypeList<>> {
    using type = TypeList<>;
};

template<template<typename> class F, typename Head, typename... Tail>
struct Transform<F, TypeList<Head, Tail...>> {
    using type = prepend_t<
        typename F<Head>::type,
        typename Transform<F, TypeList<Tail...>>::type
    >;
};

template<template<typename> class F, typename List>
using transform_t = typename Transform<F, List>::type;

// ─── Contains ────────────────────────────────────────────────────────────────
template<typename T, typename List>
struct Contains : std::false_type {};

template<typename T, typename Head, typename... Tail>
struct Contains<T, TypeList<Head, Tail...>>
    : std::conditional_t<std::is_same_v<T, Head>,
                          std::true_type,
                          Contains<T, TypeList<Tail...>>> {};

template<typename T, typename List>
constexpr bool contains_v = Contains<T, List>::value;

// ─── Demo ─────────────────────────────────────────────────────────────────────
using AllTypes = TypeList<int, double, char, float, long, short>;

// Filter: keep only integral types
using Integrals = filter_t<std::is_integral, AllTypes>;
// = TypeList<int, char, long, short>

// Transform: add const
template<typename T>
struct AddConst { using type = const T; };
using ConstIntegrals = transform_t<AddConst, Integrals>;
// = TypeList<const int, const char, const long, const short>

// Transform: add pointer
template<typename T>
struct ToPointer { using type = T*; };
using PtrTypes = transform_t<ToPointer, Integrals>;
// = TypeList<int*, char*, long*, short*>

// Compile-time assertions
static_assert(length_v<AllTypes> == 6);
static_assert(length_v<Integrals> == 4);
static_assert(std::is_same_v<at_t<0, AllTypes>, int>);
static_assert(std::is_same_v<at_t<2, AllTypes>, char>);
static_assert(std::is_same_v<at_t<0, Integrals>, int>);
static_assert(std::is_same_v<at_t<0, PtrTypes>, int*>);
static_assert(contains_v<int, AllTypes>);
static_assert(!contains_v<std::string, AllTypes>);
static_assert(std::is_same_v<at_t<0, ConstIntegrals>, const int>);

int main() {
    std::cout << "AllTypes length:   " << length_v<AllTypes>   << "\n";  // 6
    std::cout << "Integrals length:  " << length_v<Integrals>  << "\n";  // 4
    std::cout << "PtrTypes length:   " << length_v<PtrTypes>   << "\n";  // 4
    // All the interesting work happens at compile time — zero runtime overhead
}
```

**Pattern used:** Recursive template specialization — the canonical pre-C++17 technique for type list manipulation. Each operation is defined as a base case (empty list) plus a recursive case (head + tail). C++17 fold expressions simplify some operations (like `Contains`), but the recursive pattern is more general and educational.

```cpp
#include <type_traits>
#include <string>
#include <vector>
#include <iostream>

// ═══════════════════════════════════════════════════════════════════════════════
// PART 1: SFINAE (C++11/14) — detect if T has a .serialize() method
// ═══════════════════════════════════════════════════════════════════════════════

// Primary template: assumes no serialize()
template<typename T, typename = void>
struct has_serialize : std::false_type {};

// Specialization: active when T::serialize() exists and returns something
template<typename T>
struct has_serialize<T, std::void_t<decltype(std::declval<const T&>().serialize())>>
    : std::true_type {};

template<typename T>
constexpr bool has_serialize_v = has_serialize<T>::value;

// SFINAE-based dispatch
template<typename T, std::enable_if_t<has_serialize_v<T>, int> = 0>
void store(const T& obj) {
    std::cout << "[serialize] " << obj.serialize() << "\n";
}

template<typename T, std::enable_if_t<!has_serialize_v<T>, int> = 0>
void store(const T& obj) {
    std::cout << "[fallback] cannot serialize type\n";
}

// ═══════════════════════════════════════════════════════════════════════════════
// PART 2: C++20 Concepts — same detection, 10x more readable
// ═══════════════════════════════════════════════════════════════════════════════

template<typename T>
concept HasSerialize = requires(const T& t) {
    { t.serialize() } -> std::convertible_to<std::string>;
};

// Two overloads — concepts enable clean overload sets without enable_if
void store_modern(const HasSerialize auto& obj) {
    std::cout << "[concept serialize] " << obj.serialize() << "\n";
}

void store_modern(const auto& obj) requires (!HasSerialize<decltype(obj)>) {
    std::cout << "[concept fallback] cannot serialize\n";
}

// ─── Test types ───────────────────────────────────────────────────────────────
struct Serializable {
    std::string serialize() const { return "Serializable{}"; }
};

struct NotSerializable {
    int x;
};

struct AlmostSerializable {
    int serialize() const { return 42; }  // returns int, not string
};

static_assert( has_serialize_v<Serializable>);
static_assert(!has_serialize_v<NotSerializable>);
static_assert( has_serialize_v<AlmostSerializable>);  // SFINAE only checks existence

static_assert( HasSerialize<Serializable>);
static_assert(!HasSerialize<NotSerializable>);
static_assert(!HasSerialize<AlmostSerializable>);  // concept checks return type too!

int main() {
    Serializable    s;
    NotSerializable ns;

    std::cout << "SFINAE:\n";
    store(s);   // [serialize] Serializable{}
    store(ns);  // [fallback] cannot serialize type

    std::cout << "Concepts:\n";
    store_modern(s);    // [concept serialize] Serializable{}
    store_modern(ns);   // [concept fallback]
    store_modern(AlmostSerializable{});  // [concept fallback] — return type mismatch caught!
}
```

**Comparison table:**
| Feature | SFINAE | Concept |
|---|---|---|
| Checks existence | `std::void_t<expr>` | `requires { expr; }` |
| Checks return type | `std::is_same_v<decltype(...),R>` | `{ expr } -> std::same_as<R>` |
| Compose checks | `std::enable_if_t<A && B>` | `ConceptA && ConceptB` |
| Error message | Template depth 15 | "constraint not satisfied" |
| Readable | No | Yes |
| Negation | `std::enable_if_t<!cond>` | `requires (!Concept<T>)` |

`std::void_t` only checks that the expression is well-formed. The concept `{ expr } -> C<R>` additionally constrains the return type — catching `AlmostSerializable` above.

