#include <memory_resource>
#include <vector>
#include <string>
#include <list>
#include <array>
#include <iostream>
#include <chrono>

// ─── Stack allocator: monotonic_buffer_resource ───────────────────────────────
// std::pmr::monotonic_buffer_resource allocates from a fixed buffer.
// Deallocation is a no-op — everything is freed at once when the resource
// goes out of scope. Ideal for per-frame/per-request scratch allocations.

void demo_monotonic() {
    // 4KB stack buffer — no heap allocation needed for small workloads
    std::array<std::byte, 4096> stack_buf;
    std::pmr::monotonic_buffer_resource stack_res{
        stack_buf.data(), stack_buf.size(),
        std::pmr::null_memory_resource()  // crash instead of falling back to heap
    };

    // pmr::vector uses the stack_res allocator
    std::pmr::vector<int> v{&stack_res};
    v.reserve(100);
    for (int i = 0; i < 100; ++i) v.push_back(i);

    std::pmr::string s{"hello world from stack", &stack_res};

    std::cout << "sum: " << std::accumulate(v.begin(), v.end(), 0) << "\n";
    std::cout << s << "\n";
    // stack_res goes out of scope: entire buffer freed in one shot
}

// ─── Pool allocator for uniform-size objects ──────────────────────────────────
// synchronized_pool_resource maintains pools of fixed-size chunks.
// Avoids fragmentation; fast allocation/deallocation for same-size objects.
void demo_pool() {
    std::pmr::pool_options opts;
    opts.max_blocks_per_chunk = 64;
    opts.largest_required_pool_block = 512;

    std::pmr::unsynchronized_pool_resource pool{opts};
    // unsynchronized = single-threaded (no mutex overhead)

    // A list of strings — each node and string allocation comes from the pool
    std::pmr::list<std::pmr::string> words{&pool};
    for (const char* w : {"the", "quick", "brown", "fox", "jumps"}) {
        words.emplace_back(w, &pool);
    }

    for (const auto& w : words) std::cout << w << " ";
    std::cout << "\n";
}

// ─── Custom memory resource: logging allocator ────────────────────────────────
class LoggingResource : public std::pmr::memory_resource {
public:
    explicit LoggingResource(std::pmr::memory_resource* upstream
                              = std::pmr::get_default_resource())
        : upstream_{upstream} {}

    int allocation_count()   const { return allocs_; }
    std::size_t bytes_used() const { return bytes_; }

private:
    void* do_allocate(std::size_t bytes, std::size_t align) override {
        ++allocs_; bytes_ += bytes;
        std::cout << "  alloc " << bytes << " bytes (align=" << align << ")\n";
        return upstream_->allocate(bytes, align);
    }
    void do_deallocate(void* p, std::size_t bytes, std::size_t align) override {
        bytes_ -= bytes;
        upstream_->deallocate(p, bytes, align);
    }
    bool do_is_equal(const memory_resource& o) const noexcept override {
        return this == &o;
    }

    std::pmr::memory_resource* upstream_;
    int allocs_{0};
    std::size_t bytes_{0};
};

void demo_logging() {
    LoggingResource log_res;
    std::pmr::vector<std::pmr::string> v{&log_res};
    std::cout << "Allocations from pmr::vector<string> push_back x3:\n";
    v.emplace_back("short", &log_res);
    v.emplace_back("a somewhat longer string", &log_res);
    v.emplace_back("another", &log_res);
    std::cout << "Total allocations: " << log_res.allocation_count() << "\n";
}

int main() {
    std::cout << "=== monotonic (stack) ===\n"; demo_monotonic();
    std::cout << "=== pool ===\n";              demo_pool();
    std::cout << "=== logging ===\n";           demo_logging();
}
```

**PMR allocation chain:**
```
std::pmr::vector → LoggingResource → monotonic_buffer_resource → stack array
```
Each resource can delegate to an upstream. The upstream chain terminates at `new_delete_resource()` (heap) or `null_memory_resource()` (throws on overflow).

**When to use each:**
| Resource | Best for |
|---|---|
| `monotonic_buffer_resource` | Per-frame scratch; no deallocation needed |
| `unsynchronized_pool_resource` | Single-threaded, many same-size objects |
| `synchronized_pool_resource` | Multi-threaded pool |
| Custom `memory_resource` | Profiling, arenas, NUMA, GPU memory |

```cpp
#include <functional>
#include <vector>
#include <unordered_map>
#include <typeindex>
#include <memory>
#include <iostream>
#include <algorithm>

// ─── Event types (plain structs — no virtual, no base class) ─────────────────
struct KeyPressed    { int key; bool shift; };
struct MouseMoved    { float x, y; };
struct WindowResized { int width, height; };
struct NetworkPacket { std::vector<uint8_t> data; };

// ─── Typed handler list ───────────────────────────────────────────────────────
// Stores handlers for one specific event type T.
// Avoids std::function overhead by storing the lambda directly via type erasure.
template<typename EventT>
struct HandlerList {
    using Handler = std::function<void(const EventT&)>;
    std::vector<Handler> handlers;

    std::size_t subscribe(Handler h) {
        handlers.push_back(std::move(h));
        return handlers.size() - 1;  // subscription ID
    }

    void unsubscribe(std::size_t id) {
        if (id < handlers.size()) handlers[id] = nullptr;
    }

    void dispatch(const EventT& event) {
        for (const auto& h : handlers)
            if (h) h(event);
    }
};

// ─── Type-erased base so we can store in a map ────────────────────────────────
struct HandlerBase {
    virtual ~HandlerBase() = default;
};

template<typename EventT>
struct HandlerHolder final : HandlerBase {
    HandlerList<EventT> list;
};

// ─── Event dispatcher ─────────────────────────────────────────────────────────
class EventDispatcher {
public:
    // Subscribe: returns a subscription token (event type + id)
    template<typename EventT, typename F>
    auto subscribe(F&& handler) -> std::pair<std::type_index, std::size_t> {
        auto& holder = get_or_create<EventT>();
        std::size_t id = holder.list.subscribe(std::forward<F>(handler));
        return {typeid(EventT), id};
    }

    // Unsubscribe by token
    template<typename EventT>
    void unsubscribe(std::size_t id) {
        if (auto it = handlers_.find(typeid(EventT)); it != handlers_.end()) {
            static_cast<HandlerHolder<EventT>*>(it->second.get())->list.unsubscribe(id);
        }
    }

    // Dispatch: looks up handlers for EventT and calls them all
    template<typename EventT>
    void dispatch(const EventT& event) {
        if (auto it = handlers_.find(typeid(EventT)); it != handlers_.end()) {
            static_cast<HandlerHolder<EventT>*>(it->second.get())->list.dispatch(event);
        }
    }

    // Dispatch rvalue
    template<typename EventT>
    void dispatch(EventT&& event) {
        dispatch(static_cast<const EventT&>(event));
    }

private:
    template<typename EventT>
    HandlerHolder<EventT>& get_or_create() {
        auto key = std::type_index{typeid(EventT)};
        auto& ptr = handlers_[key];
        if (!ptr) ptr = std::make_unique<HandlerHolder<EventT>>();
        return *static_cast<HandlerHolder<EventT>*>(ptr.get());
    }

    std::unordered_map<std::type_index, std::unique_ptr<HandlerBase>> handlers_;
};

// ─── Demo ─────────────────────────────────────────────────────────────────────
int main() {
    EventDispatcher dispatcher;

    // Subscribe multiple handlers for the same event type
    auto [_, key_sub1] = dispatcher.subscribe<KeyPressed>([](const KeyPressed& e) {
        std::cout << "Handler1: key=" << e.key << (e.shift ? " [SHIFT]" : "") << "\n";
    });

    dispatcher.subscribe<KeyPressed>([](const KeyPressed& e) {
        std::cout << "Handler2: key=" << e.key << "\n";
    });

    dispatcher.subscribe<MouseMoved>([](const MouseMoved& e) {
        std::cout << "Mouse: (" << e.x << "," << e.y << ")\n";
    });

    dispatcher.subscribe<WindowResized>([](const WindowResized& e) {
        std::cout << "Window: " << e.width << "x" << e.height << "\n";
    });

    // Dispatch
    dispatcher.dispatch(KeyPressed{65, true});       // A + Shift
    dispatcher.dispatch(MouseMoved{100.5f, 200.0f});
    dispatcher.dispatch(WindowResized{1920, 1080});

    // Unsubscribe first key handler
    dispatcher.unsubscribe<KeyPressed>(key_sub1);
    std::cout << "After unsubscribe:\n";
    dispatcher.dispatch(KeyPressed{66, false});  // only Handler2 fires
}
```

**Design trade-offs:**
- `std::type_index` lookup is O(1) hash, not compile-time — adds ~one hash lookup per dispatch.
- For truly zero-overhead compile-time dispatch, use a compile-time map (template specializations) with fixed event types — see the FSM example for the pattern.
- `std::function` has overhead (type erasure, heap allocation for large captures). For hot paths, use a template `F` stored in a `std::vector<std::any>` or intrusive linked list.

```cpp
#include <array>
#include <string_view>
#include <cstdint>
#include <stdexcept>
#include <iostream>
#include <algorithm>

// ─── Compile-time perfect hash for a fixed string key set ─────────────────────
// Strategy: try hash functions h(s) = fnv(salt ^ s) % N until we find one
// with no collisions for our key set. All computation happens at compile time.

constexpr uint32_t fnv_hash(uint32_t salt, std::string_view s) noexcept {
    uint32_t h = 2166136261u ^ salt;
    for (unsigned char c : s) {
        h ^= c;
        h *= 16777619u;
    }
    return h;
}

template<std::size_t N>
constexpr std::array<std::string_view, N>
make_key_array(std::initializer_list<std::string_view> keys) {
    std::array<std::string_view, N> arr{};
    std::size_t i = 0;
    for (auto k : keys) arr[i++] = k;
    return arr;
}

// Search for a salt that produces a perfect hash for the given keys
template<std::size_t N>
constexpr uint32_t find_perfect_salt(const std::array<std::string_view, N>& keys) {
    for (uint32_t salt = 0; salt < 100000; ++salt) {
        std::array<bool, N> used{};
        bool ok = true;
        for (const auto& k : keys) {
            std::size_t slot = fnv_hash(salt, k) % N;
            if (used[slot]) { ok = false; break; }
            used[slot] = true;
        }
        if (ok) return salt;
    }
    throw std::runtime_error{"no perfect salt found — try larger N"};
}

// ─── Compile-time perfect hash table ─────────────────────────────────────────
template<typename V, std::size_t N>
struct PerfectHashTable {
    struct Entry {
        std::string_view key;
        V value{};
        bool occupied = false;
    };

    std::array<Entry, N> table{};
    uint32_t salt;

    constexpr std::size_t slot(std::string_view k) const noexcept {
        return fnv_hash(salt, k) % N;
    }

    constexpr const V* find(std::string_view k) const noexcept {
        auto& e = table[slot(k)];
        return (e.occupied && e.key == k) ? &e.value : nullptr;
    }

    // Must be called during construction only
    constexpr void insert(std::string_view k, V v) {
        auto& e = table[slot(k)];
        e = {k, std::move(v), true};
    }
};

// ─── Factory consteval function ───────────────────────────────────────────────
consteval auto build_http_status_table() {
    constexpr auto keys = make_key_array<8>(
        {"200", "201", "400", "401", "403", "404", "500", "503"});
    constexpr uint32_t salt = find_perfect_salt(keys);

    PerfectHashTable<std::string_view, 8> t;
    t.salt = salt;
    t.insert("200", "OK");
    t.insert("201", "Created");
    t.insert("400", "Bad Request");
    t.insert("401", "Unauthorized");
    t.insert("403", "Forbidden");
    t.insert("404", "Not Found");
    t.insert("500", "Internal Server Error");
    t.insert("503", "Service Unavailable");
    return t;
}

constexpr auto HTTP_STATUS = build_http_status_table();

// ─── Compile-time verification ────────────────────────────────────────────────
static_assert(*HTTP_STATUS.find("200") == "OK");
static_assert(*HTTP_STATUS.find("404") == "Not Found");
static_assert( HTTP_STATUS.find("999") == nullptr);

int main() {
    const char* codes[] = {"200", "400", "404", "500", "418"};
    for (auto code : codes) {
        if (auto* desc = HTTP_STATUS.find(code))
            std::cout << code << ": " << *desc << "\n";
        else
            std::cout << code << ": unknown\n";
    }
    // 200: OK
    // 400: Bad Request
    // 404: Not Found
    // 500: Internal Server Error
    // 418: unknown
}
```

**Runtime complexity:** O(1) lookup — exactly one hash computation and one array access. No chaining, no probing. The salt search happens entirely at compile time and is discarded; only the final table lives in the binary (in `.rodata`). For 8 keys, `find_perfect_salt` typically terminates within the first 50 iterations.

