// ════════════════════════════════════════════════════════════════════════════
// File: math.cppm  (Module Interface Unit)
// Compiled with: g++ -std=c++20 -fmodules-ts -c math.cppm
// ════════════════════════════════════════════════════════════════════════════

export module math;  // Declares 'math' module, this file is the primary interface unit

import <cmath>;       // Import standard library headers as modules (GCC 11+ / Clang 14+)
import <stdexcept>;

// export: visible to importers
// (no export): internal linkage within the module

export namespace math {

    // Exported function — declaration AND definition in interface unit
    [[nodiscard]] constexpr double square(double x) noexcept {
        return x * x;
    }

    // Exported type
    struct Vec2 {
        double x, y;
        constexpr Vec2(double x, double y) noexcept : x{x}, y{y} {}
        constexpr Vec2 operator+(const Vec2& o) const noexcept { return {x+o.x, y+o.y}; }
        constexpr Vec2 operator*(double s)       const noexcept { return {x*s, y*s}; }
        [[nodiscard]] double length() const noexcept { return std::hypot(x, y); }
        [[nodiscard]] Vec2   normalize() const {
            double len = length();
            if (len == 0) throw std::domain_error{"cannot normalize zero vector"};
            return {x/len, y/len};
        }
    };

    // Exported function whose implementation is in the implementation unit
    export double solve_quadratic(double a, double b, double c);

}  // namespace math

// Internal helper — NOT exported, invisible to importers
namespace detail {
    double discriminant(double a, double b, double c) {
        return b*b - 4*a*c;
    }
}

// ════════════════════════════════════════════════════════════════════════════
// File: math_impl.cpp  (Module Implementation Unit)
// ════════════════════════════════════════════════════════════════════════════

module math;  // Belongs to 'math' module (no 'export' keyword here)

import <cmath>;
import <stdexcept>;

// Implements the function declared in the interface unit
namespace math {
    double solve_quadratic(double a, double b, double c) {
        double disc = b*b - 4*a*c;
        if (disc < 0) throw std::domain_error{"no real roots"};
        double sq = std::sqrt(disc);
        // Returns the larger root
        return (-b + sq) / (2 * a);
    }
}

// ════════════════════════════════════════════════════════════════════════════
// File: main.cpp  (Consumer)
// Compiled with: g++ -std=c++20 -fmodules-ts math.cppm math_impl.cpp main.cpp
// ════════════════════════════════════════════════════════════════════════════

import math;   // replaces: #include "math.h"
import <iostream>;

int main() {
    // Use exported types and functions
    math::Vec2 a{3, 0}, b{0, 4};
    auto c = a + b;
    std::cout << "length: " << c.length() << "\n";  // 5

    auto n = c.normalize();
    std::cout << "normalized: (" << n.x << "," << n.y << ")\n";

    std::cout << "square(7): " << math::square(7) << "\n";  // 49

    // x^2 - 5x + 6 = 0 → roots are 3 and 2
    std::cout << "root: " << math::solve_quadratic(1, -5, 6) << "\n";  // 3

    // detail::discriminant is NOT accessible — not exported
    // detail::discriminant(1,2,3);  // compile error
}
```

**Modules vs headers:**
| | Headers | Modules |
|---|---|---|
| Compilation | Re-parsed per TU | Compiled once, binary interface cached |
| Macro leakage | Yes | No — modules don't export macros |
| Order dependency | Include order matters | Import order irrelevant |
| Encapsulation | None (`static` / anon ns) | Non-exported names invisible to importers |
| Build speed | Slow (millions of lines re-parsed) | Fast (pre-compiled BMI loaded) |

**Compiler support (as of 2025):**
- GCC 11+ with `-fmodules-ts`
- Clang 14+ with `-fmodules`
- MSVC 2019 16.8+ natively
- CMake 3.28+ supports modules via `target_sources(... CXX_MODULES ...)`.

