// Encode SI dimensions as template parameters [Length, Time, Mass]
template<int L, int T, int M> struct Dimension {};

using DimLength   = Dimension< 1, 0, 0>;
using DimTime     = Dimension< 0, 1, 0>;
using DimMass     = Dimension< 0, 0, 1>;
using DimVelocity = Dimension< 1,-1, 0>;
using DimAccel    = Dimension< 1,-2, 0>;
using DimForce    = Dimension< 1,-2, 1>;

template<typename D1, typename D2> struct MulDim;
template<int L1,int T1,int M1,int L2,int T2,int M2>
struct MulDim<Dimension<L1,T1,M1>,Dimension<L2,T2,M2>> {
    using type = Dimension<L1+L2,T1+T2,M1+M2>;
};
template<typename D1,typename D2>
using mul_dim_t = typename MulDim<D1,D2>::type;

template<typename D1, typename D2> struct DivDim;
template<int L1,int T1,int M1,int L2,int T2,int M2>
struct DivDim<Dimension<L1,T1,M1>,Dimension<L2,T2,M2>> {
    using type = Dimension<L1-L2,T1-T2,M1-M2>;
};
template<typename D1,typename D2>
using div_dim_t = typename DivDim<D1,D2>::type;

template<typename Dim>
struct Quantity {
    double value;
    explicit constexpr Quantity(double v=0) noexcept : value{v} {}

    Quantity operator+(Quantity o) const noexcept { return Quantity{value+o.value}; }
    Quantity operator-(Quantity o) const noexcept { return Quantity{value-o.value}; }
    Quantity operator*(double s)   const noexcept { return Quantity{value*s}; }
    Quantity operator/(double s)   const noexcept { return Quantity{value/s}; }

    template<typename D2>
    Quantity<mul_dim_t<Dim,D2>> operator*(Quantity<D2> o) const noexcept {
        return Quantity<mul_dim_t<Dim,D2>>{value*o.value};
    }
    template<typename D2>
    Quantity<div_dim_t<Dim,D2>> operator/(Quantity<D2> o) const noexcept {
        return Quantity<div_dim_t<Dim,D2>>{value/o.value};
    }
};

using Meters    = Quantity<DimLength>;
using Seconds   = Quantity<DimTime>;
using Kilograms = Quantity<DimMass>;
using MPS       = Quantity<DimVelocity>;
using Newtons   = Quantity<DimForce>;

constexpr Meters    operator""_m (long double v) { return Meters   {(double)v}; }
constexpr Seconds   operator""_s (long double v) { return Seconds  {(double)v}; }
constexpr Kilograms operator""_kg(long double v) { return Kilograms{(double)v}; }

int main() {
    auto dist  = 100.0_m;
    auto time  = 9.58_s;
    auto speed = dist / time;   // Quantity<DimVelocity>
    std::cout << "Speed: " << speed.value << " m/s\n"; // ~10.44

    auto mass  = 86.0_kg;
    auto accel = speed / time;
    auto force = mass * accel;  // Quantity<DimForce>
    std::cout << "Force: " << force.value << " N\n";

    // COMPILE ERROR -- no operator+ between different dimensions:
    // auto wrong = dist + time;

    static_assert(std::is_same_v<decltype(speed), MPS>);
    static_assert(std::is_same_v<decltype(force), Newtons>);
    std::cout << "Type checks passed\n";
}
```

Unit mismatches are compile errors, not runtime errors. `Quantity<Dimension<1,-1,0>>` encodes 'meters per second' in the type system. Adding Meters + Seconds fails to compile because there is no `operator+` between `Quantity<Dimension<1,0,0>>` and `Quantity<Dimension<0,1,0>>`. The dimensional type is carried entirely in the template parameter — zero runtime overhead.

```cpp
#include <unordered_map>
#include <list>
#include <optional>
#include <stdexcept>
#include <iostream>
#include <string>
#include <functional>

template<typename K, typename V, typename Hash = std::hash<K>>
class LRUCache {
public:
    explicit LRUCache(std::size_t capacity) : capacity_{capacity} {
        if (capacity == 0) throw std::invalid_argument{"capacity must be > 0"};
    }

    // O(1): returns nullopt if not present; moves to MRU position
    std::optional<V> get(const K& key) {
        auto it = index_.find(key);
        if (it == index_.end()) { ++misses_; return std::nullopt; }
        ++hits_;
        items_.splice(items_.begin(), items_, it->second);
        return it->second->second;
    }

    // O(1): insert or update; evicts LRU if at capacity
    void put(const K& key, V value) {
        auto it = index_.find(key);
        if (it != index_.end()) {
            it->second->second = std::move(value);
            items_.splice(items_.begin(), items_, it->second);
            return;
        }
        if (items_.size() == capacity_) {
            index_.erase(items_.back().first);
            items_.pop_back();
        }
        items_.emplace_front(key, std::move(value));
        index_[key] = items_.begin();
    }

    bool contains(const K& key) const { return index_.count(key) > 0; }
    std::size_t size() const noexcept { return items_.size(); }
    std::size_t capacity() const noexcept { return capacity_; }
    double hit_rate() const noexcept {
        auto total = hits_ + misses_;
        return total ? double(hits_) / total : 0.0;
    }

private:
    using Item = std::pair<K, V>;
    std::size_t capacity_;
    std::list<Item> items_;   // MRU at front, LRU at back
    std::unordered_map<K, typename std::list<Item>::iterator, Hash> index_;
    std::size_t hits_{0}, misses_{0};
};

int main() {
    LRUCache<std::string, int> cache{3};
    cache.put("a", 1);
    cache.put("b", 2);
    cache.put("c", 3);
    cache.get("a");        // touch "a" -> MRU: a, c, b
    cache.put("d", 4);     // evicts "b" (LRU)

    std::cout << "a: " << cache.get("a").value_or(-1) << "\n"; // 1
    std::cout << "b: " << cache.get("b").value_or(-1) << "\n"; // -1 (evicted)
    std::cout << "d: " << cache.get("d").value_or(-1) << "\n"; // 4
    std::cout << "hit_rate: " << cache.hit_rate() << "\n";       // ~0.67

    LRUCache<int, long long> fib_cache{100};
    std::function<long long(int)> fib = [&](int n) -> long long {
        if (n <= 1) return n;
        if (auto v = fib_cache.get(n)) return *v;
        auto result = fib(n-1) + fib(n-2);
        fib_cache.put(n, result);
        return result;
    };
    std::cout << "fib(40)=" << fib(40) << "\n"; // 102334155
}
```

**Complexity:** `get` and `put` are both O(1) amortized. `list::splice` is O(1) — it relinks three pointers, no memory allocation. `unordered_map` gives O(1) amortized lookup. The LRU invariant is maintained by list order: front = MRU, back = LRU. Eviction removes the back element and erases the corresponding map entry in O(1).

```cpp
#include <type_traits>
#include <vector>
#include <list>
#include <optional>
#include <memory>
#include <tuple>
#include <variant>
#include <iostream>

// Detect if T is a specialization of Template (variadic type params)
template<typename T, template<typename...> class Template>
struct is_specialization : std::false_type {};

template<typename... Args, template<typename...> class Template>
struct is_specialization<Template<Args...>, Template> : std::true_type {};

template<typename T, template<typename...> class Template>
constexpr bool is_specialization_v = is_specialization<T, Template>::value;

// Concept wrapper
template<typename T, template<typename...> class Template>
concept Specialization = is_specialization_v<T, Template>;

// Specific helpers
template<typename T> constexpr bool is_optional_v    = is_specialization_v<T, std::optional>;
template<typename T> constexpr bool is_vector_v      = is_specialization_v<T, std::vector>;
template<typename T> constexpr bool is_shared_ptr_v  = is_specialization_v<T, std::shared_ptr>;

// Concept-constrained function: only accepts vector specializations
template<Specialization<std::vector> V>
void process_vector(const V& v) {
    std::cout << "vector of " << v.size() << " elements\n";
}

// Flatten optional<optional<T>> -> optional<T>
template<typename T>
    requires is_optional_v<T> && is_optional_v<typename T::value_type>
auto flatten(T opt_opt) -> typename T::value_type {
    if (!opt_opt) return std::nullopt;
    return *opt_opt;
}

// Unwrap optional if it is one, else return as-is
template<typename T>
auto unwrap_or(const T& val, auto fallback) {
    if constexpr (is_optional_v<std::decay_t<T>>)
        return val.value_or(fallback);
    else
        return val;
}

int main() {
    static_assert( is_specialization_v<std::vector<int>,     std::vector>);
    static_assert( is_specialization_v<std::list<float>,     std::list>);
    static_assert( is_specialization_v<std::optional<int>,   std::optional>);
    static_assert( is_specialization_v<std::shared_ptr<int>, std::shared_ptr>);
    static_assert( is_specialization_v<std::tuple<int,double,char>, std::tuple>);
    static_assert( is_specialization_v<std::variant<int,float>,     std::variant>);
    static_assert(!is_specialization_v<int,        std::vector>);
    static_assert(!is_specialization_v<std::string,std::vector>);

    static_assert( is_optional_v<std::optional<int>>);
    static_assert(!is_optional_v<int>);
    static_assert(!is_optional_v<std::vector<int>>);

    process_vector(std::vector<int>{1,2,3});
    process_vector(std::vector<std::string>{"a","b"});
    // process_vector(std::list<int>{});  // compile error

    std::cout << unwrap_or(std::optional<int>{42}, 0)  << "\n"; // 42
    std::cout << unwrap_or(99, 0) << "\n";                       // 99

    std::optional<std::optional<int>> nested{std::optional<int>{7}};
    std::cout << flatten(nested).value_or(-1) << "\n"; // 7
    std::cout << "All checks passed\n";
}
```

**How it works:** The partial specialization `is_specialization<Template<Args...>, Template>` matches when `T` is exactly `Template` applied to some `Args...`. The primary template catches everything else with `false_type`. This works for any template with type-only parameters (vector, optional, tuple, variant, shared_ptr). Non-type template parameters like `std::array<T,N>` require a separate specialization:
```cpp
template<typename T, std::size_t N>
struct is_specialization<std::array<T,N>, std::array> : std::true_type {};
```
